       SUM(CASE WHEN wam_sessions IS NULL THEN 1 ELSE 0 END) AS wam_sessions_nulls,
       SUM(CASE WHEN GCR IS NULL THEN 1 ELSE 0 END) AS gcr_nulls
FROM dev.ba_corporate.wam_site_performance;
